import { Component } from '@angular/core';
import { FormBuilder, Validators } from '@angular/forms';
import { ResumeService } from '../../../core/services/resume.service';

@Component({
  selector: 'app-template-upload',
  templateUrl: './template-upload.component.html'
})
export class TemplateUploadComponent {
  previewImage: File | null = null;
  htmlTemplateFile: File | null = null;
  submitting = false;
  error = '';
  success = '';

  readonly form = this.formBuilder.group({
    name: ['', Validators.required],
    category: ['', Validators.required],
    atsFriendly: [true, Validators.required],
    premium: [false, Validators.required]
  });

  constructor(
    private readonly formBuilder: FormBuilder,
    private readonly resumeService: ResumeService
  ) {
  }

  onPreviewImageSelected(event: Event): void {
    const input = event.target as HTMLInputElement;
    this.previewImage = input.files?.[0] ?? null;
  }

  onTemplateFileSelected(event: Event): void {
    const input = event.target as HTMLInputElement;
    this.htmlTemplateFile = input.files?.[0] ?? null;
  }

  submit(): void {
    if (this.form.invalid || !this.previewImage) {
      this.form.markAllAsTouched();
      this.error = 'Name, category, and preview image are required.';
      return;
    }

    this.submitting = true;
    this.error = '';
    this.success = '';

    const value = this.form.getRawValue();
    this.resumeService.uploadAdminTemplate({
      name: value.name ?? '',
      category: value.category ?? '',
      atsFriendly: !!value.atsFriendly,
      premium: !!value.premium,
      previewImage: this.previewImage,
      htmlTemplateFile: this.htmlTemplateFile
    }).subscribe({
      next: () => {
        this.submitting = false;
        this.success = 'Template uploaded. Users can now pick and edit it.';
        this.form.reset({
          name: '',
          category: '',
          atsFriendly: true,
          premium: false
        });
        this.previewImage = null;
        this.htmlTemplateFile = null;
      },
      error: (error: { error?: { message?: string } }) => {
        this.submitting = false;
        this.error = error.error?.message ?? 'Template upload failed.';
      }
    });
  }
}
<div class="mx-auto max-w-4xl space-y-6">
  <div class="glass-panel p-6">
    <p class="text-sm font-semibold uppercase tracking-[0.28em] text-poppy">Admin Template Upload</p>
    <h2 class="section-title mt-2 text-4xl">Upload an editable ATS template</h2>
    <p class="mt-4 max-w-3xl text-base leading-7 text-ink/65">
      Upload the preview image users should see in the template gallery and optionally upload the HTML template file they will actually edit.
      Use placeholders like <code ngNonBindable>{{fullName}}</code>, <code ngNonBindable>{{headline}}</code>, <code ngNonBindable>{{email}}</code>,
      <code ngNonBindable>{{phone}}</code>, <code ngNonBindable>{{links}}</code>, and section placeholders like <code ngNonBindable>{{projectsSection}}</code>.
    </p>
  </div>

  <form class="glass-panel space-y-5 p-6" [formGroup]="form" (ngSubmit)="submit()">
    <div class="grid gap-4 md:grid-cols-2">
      <input class="field" formControlName="name" placeholder="Template name">
      <input class="field" formControlName="category" placeholder="Category">
    </div>

    <div class="grid gap-4 md:grid-cols-2">
      <label class="flex items-center gap-3 rounded-2xl border border-black/10 bg-white/90 px-4 py-3 text-sm text-ink">
        <input type="checkbox" formControlName="atsFriendly">
        ATS-friendly
      </label>
      <label class="flex items-center gap-3 rounded-2xl border border-black/10 bg-white/90 px-4 py-3 text-sm text-ink">
        <input type="checkbox" formControlName="premium">
        Premium template
      </label>
    </div>

    <div class="grid gap-4 md:grid-cols-2">
      <div>
        <label class="mb-2 block text-sm font-semibold text-ink/70">Preview image</label>
        <input class="field" type="file" accept="image/*" (change)="onPreviewImageSelected($event)">
      </div>
      <div>
        <label class="mb-2 block text-sm font-semibold text-ink/70">HTML template file</label>
        <input class="field" type="file" accept=".html,text/html" (change)="onTemplateFileSelected($event)">
        <p class="mt-2 text-xs leading-6 text-ink/55">
          Optional. If skipped, users will still see this uploaded template card and edit it using the default ATS-friendly editable layout.
        </p>
      </div>
    </div>

    <p *ngIf="error" class="rounded-2xl bg-poppy/10 px-4 py-3 text-sm font-medium text-poppy">{{ error }}</p>
    <p *ngIf="success" class="rounded-2xl bg-pine/10 px-4 py-3 text-sm font-medium text-pine">{{ success }}</p>

    <div class="flex gap-3">
      <button class="btn-primary" type="submit" [disabled]="submitting">{{ submitting ? 'Uploading...' : 'Upload Template' }}</button>
      <a routerLink="/resume-builder/templates" class="btn-secondary">View Template Gallery</a>
    </div>
  </form>
</div>
